DELIMITER $$
--
-- Procedimientos
--
CREATE PROCEDURE `sp_buscar_noticias` (IN `p_texto` VARCHAR(200), IN `p_categoria` INT UNSIGNED, IN `p_fecha_desde` DATE, IN `p_fecha_hasta` DATE, IN `p_limite` INT, IN `p_offset` INT)   BEGIN
    SELECT n.id, n.titulo, n.slug, n.resumen, n.imagen,
           n.vistas, n.fecha_publicacion, n.tiempo_lectura,
           u.nombre AS autor_nombre,
           c.nombre AS categoria_nombre,
           c.color  AS categoria_color, c.icono AS categoria_icono
    FROM noticias n
    INNER JOIN usuarios   u ON u.id = n.autor_id
    INNER JOIN categorias c ON c.id = n.categoria_id
    WHERE n.estado = 'publicado'
      AND n.fecha_publicacion <= NOW()
      AND (p_texto IS NULL
           OR MATCH(n.titulo, n.resumen, n.contenido) AGAINST(p_texto IN BOOLEAN MODE))
      AND (p_categoria IS NULL OR n.categoria_id = p_categoria)
      AND (p_fecha_desde IS NULL OR DATE(n.fecha_publicacion) >= p_fecha_desde)
      AND (p_fecha_hasta IS NULL OR DATE(n.fecha_publicacion) <= p_fecha_hasta)
    ORDER BY
        CASE WHEN p_texto IS NOT NULL
             THEN MATCH(n.titulo, n.resumen, n.contenido) AGAINST(p_texto)
             ELSE 0 END DESC,
        n.fecha_publicacion DESC
    LIMIT p_limite OFFSET p_offset;
END$$

CREATE PROCEDURE `sp_incrementar_visita` (IN `p_noticia_id` INT UNSIGNED, IN `p_ip` VARCHAR(45), IN `p_user_agent` VARCHAR(500), IN `p_dispositivo` ENUM('desktop','tablet','mobile'))   BEGIN
    DECLARE v_existe INT DEFAULT 0;
    SELECT COUNT(*) INTO v_existe
    FROM visitas_log
    WHERE noticia_id = p_noticia_id
      AND ip = p_ip
      AND fecha >= NOW() - INTERVAL 1 HOUR;
    IF v_existe = 0 THEN
        VALUES (p_noticia_id, p_ip, p_user_agent, p_dispositivo);
        UPDATE noticias SET vistas = vistas + 1 WHERE id = p_noticia_id;
    END IF;
END$$

CREATE PROCEDURE `sp_otorgar_insignias` (IN `p_usuario_id` INT UNSIGNED)   BEGIN
    DECLARE v_comentarios INT DEFAULT 0;
    DECLARE v_likes       INT DEFAULT 0;
    DECLARE v_premium     INT DEFAULT 0;
    DECLARE v_verificado  INT DEFAULT 0;

    SELECT COUNT(*) INTO v_comentarios
    FROM `comentarios`
    WHERE `usuario_id` = p_usuario_id AND `aprobado` = 1;

    SELECT COALESCE(SUM(`likes`), 0) INTO v_likes
    FROM `comentarios`
    WHERE `usuario_id` = p_usuario_id AND `aprobado` = 1;

    SELECT `premium`    INTO v_premium    FROM `usuarios` WHERE `id` = p_usuario_id LIMIT 1;
    SELECT `verificado` INTO v_verificado FROM `usuarios` WHERE `id` = p_usuario_id LIMIT 1;

    IF v_comentarios >= 10  THEN INSERT IGNORE INTO `usuario_insignias`(`usuario_id`,`insignia_id`) VALUES(p_usuario_id, 1); END IF;
    IF v_comentarios >= 50  THEN INSERT IGNORE INTO `usuario_insignias`(`usuario_id`,`insignia_id`) VALUES(p_usuario_id, 2); END IF;
    IF v_comentarios >= 100 THEN INSERT IGNORE INTO `usuario_insignias`(`usuario_id`,`insignia_id`) VALUES(p_usuario_id, 3); END IF;
    IF v_likes       >= 100 THEN INSERT IGNORE INTO `usuario_insignias`(`usuario_id`,`insignia_id`) VALUES(p_usuario_id, 4); END IF;
    IF v_verificado  = 1    THEN INSERT IGNORE INTO `usuario_insignias`(`usuario_id`,`insignia_id`) VALUES(p_usuario_id, 5); END IF;
    IF v_premium     = 1    THEN INSERT IGNORE INTO `usuario_insignias`(`usuario_id`,`insignia_id`) VALUES(p_usuario_id, 6); END IF;

    UPDATE `usuarios`
       SET `reputacion` = (v_comentarios * 2 + v_likes)
     WHERE `id` = p_usuario_id;
END$$

CREATE PROCEDURE `sp_registrar_compartido` (IN `p_noticia_id` INT UNSIGNED, IN `p_red` VARCHAR(20), IN `p_usuario_id` INT UNSIGNED, IN `p_ip` VARCHAR(45))   BEGIN
    VALUES (p_noticia_id, p_red, p_usuario_id, p_ip);
    UPDATE `noticias`
       SET `total_compartidos` = `total_compartidos` + 1
     WHERE `id` = p_noticia_id;
END$$

DELIMITER ;

