--
-- Disparadores `encuestas`
--
DELIMITER $$
CREATE TRIGGER `trg_enc_fecha_cierre_insert` BEFORE INSERT ON `encuestas` FOR EACH ROW BEGIN
  IF NEW.fecha_cierre IS NULL AND NEW.fecha_fin IS NOT NULL THEN
    SET NEW.fecha_cierre = NEW.fecha_fin;
  END IF;
  IF NEW.fecha_fin IS NULL AND NEW.fecha_cierre IS NOT NULL THEN
    SET NEW.fecha_fin = NEW.fecha_cierre;
  END IF;
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_enc_fecha_cierre_update` BEFORE UPDATE ON `encuestas` FOR EACH ROW BEGIN
  IF NEW.fecha_cierre != OLD.fecha_cierre THEN
    SET NEW.fecha_fin = NEW.fecha_cierre;
  ELSEIF NEW.fecha_fin != OLD.fecha_fin THEN
    SET NEW.fecha_cierre = NEW.fecha_fin;
  END IF;
END
$$
DELIMITER ;

