--
-- Estructura para la vista `v_estadisticas_admin`
--
DROP TABLE IF EXISTS `v_estadisticas_admin`;

CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `v_estadisticas_admin`  AS SELECT (select count(0) from `noticias` where `noticias`.`estado` = 'publicado') AS `noticias_publicadas`, (select count(0) from `noticias` where `noticias`.`estado` = 'borrador') AS `noticias_borrador`, (select count(0) from `usuarios` where `usuarios`.`activo` = 1) AS `usuarios_activos`, (select count(0) from `usuarios` where `usuarios`.`premium` = 1) AS `usuarios_premium`, (select count(0) from `comentarios` where `comentarios`.`aprobado` = 1) AS `total_comentarios`, (select sum(`noticias`.`vistas`) from `noticias` where `noticias`.`estado` = 'publicado') AS `total_visitas`, (select count(0) from `newsletter_suscriptores` where `newsletter_suscriptores`.`confirmado` = 1 and `newsletter_suscriptores`.`activo` = 1) AS `suscriptores_activos`, (select count(0) from `anuncios` where `anuncios`.`activo` = 1) AS `anuncios_activos`, (select count(0) from `videos` where `videos`.`activo` = 1) AS `videos_activos`, (select count(0) from `live_blog` where `live_blog`.`estado` = 'activo') AS `live_activos`, (select sum(`anuncios`.`clics`) from `anuncios`) AS `total_clics_ads`, (select count(0) from `reportes_contenido` where `reportes_contenido`.`estado` = 'pendiente') AS `reportes_pendientes` ;

-- --------------------------------------------------------

--
-- Estructura para la vista `v_noticias_publicadas`
--
DROP TABLE IF EXISTS `v_noticias_publicadas`;

CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `v_noticias_publicadas`  AS SELECT `n`.`id` AS `id`, `n`.`titulo` AS `titulo`, `n`.`slug` AS `slug`, `n`.`resumen` AS `resumen`, `n`.`imagen` AS `imagen`, `n`.`imagen_alt` AS `imagen_alt`, `n`.`vistas` AS `vistas`, `n`.`compartidos` AS `compartidos`, `n`.`likes` AS `likes`, `n`.`destacado` AS `destacado`, `n`.`breaking` AS `breaking`, `n`.`es_premium` AS `es_premium`, `n`.`es_opinion` AS `es_opinion`, `n`.`tiempo_lectura` AS `tiempo_lectura`, `n`.`allow_comments` AS `allow_comments`, `n`.`video_url` AS `video_url`, `n`.`encuesta_id` AS `encuesta_id`, `n`.`fecha_publicacion` AS `fecha_publicacion`, `n`.`fecha_actualizacion` AS `fecha_actualizacion`, `u`.`id` AS `autor_id`, `u`.`nombre` AS `autor_nombre`, `u`.`avatar` AS `autor_avatar`, `u`.`slug_perfil` AS `autor_slug`, `u`.`verificado` AS `autor_verificado`, `c`.`id` AS `categoria_id`, `c`.`nombre` AS `categoria_nombre`, `c`.`slug` AS `categoria_slug`, `c`.`color` AS `categoria_color`, `c`.`icono` AS `categoria_icono`, (select count(0) from `comentarios` `co` where `co`.`noticia_id` = `n`.`id` and `co`.`aprobado` = 1) AS `total_comentarios`, (select count(0) from `favoritos` `fv` where `fv`.`noticia_id` = `n`.`id`) AS `total_favoritos`, (select count(0) from `reacciones` `re` where `re`.`noticia_id` = `n`.`id`) AS `total_reacciones` FROM ((`noticias` `n` join `usuarios` `u` on(`u`.`id` = `n`.`autor_id`)) join `categorias` `c` on(`c`.`id` = `n`.`categoria_id`)) WHERE `n`.`estado` = 'publicado' AND `n`.`fecha_publicacion` <= current_timestamp() ;

